async function auditCmd(type) {
    if (selectedDeviceIds.size === 0) return toast("SELECT TARGETS TO AUDIT", "danger");

    document.getElementById('status-title').innerText = `CLUSTER AUDIT: ${type}`;
    document.getElementById('status-content').innerHTML = '<div style="padding:20px; text-align:center;">FETCHING CLUSTER DATA...</div>';
    document.getElementById('status-overlay').style.display = 'flex';

    const { data, error } = await sb.from('file_commands')
        .select('*')
        .eq('file_name', type)
        .in('device_id', Array.from(selectedDeviceIds))
        .order('created_at', { ascending: false })
        .limit(15);

    if (error) return document.getElementById('status-content').innerHTML = `Error: ${error.message}`;

    document.getElementById('status-content').innerHTML = data.map(c => {
        let statusCol = 'var(--text)';
        if (c.status === 'PENDING') statusCol = '#f59e0b';
        if (c.status === 'RECEIVED') statusCol = 'var(--primary)';
        if (c.status === 'EXECUTED' || c.status.includes('SUCCESS')) statusCol = 'var(--success)';
        if (c.status.includes('FAILED') || c.status.includes('ERROR')) statusCol = 'var(--danger)';

        return `
            <div class="card" style="margin-bottom:10px; border-left-color: ${statusCol}">
                <div style="display:flex; justify-content:space-between; font-size:0.7rem; color:#666; margin-bottom:5px;">
                    <span>ID: ${c.device_id.substring(0,8)}...</span>
                    <span>${new Date(c.created_at).toLocaleString()}</span>
                </div>
                <div style="font-size:0.85rem; font-weight:bold; color:${statusCol}">${c.status}</div>
                <div style="font-size:0.75rem; color:#aaa; margin-top:5px; background:rgba(0,0,0,0.3); padding:5px;">${c.content.substring(0,60)}${c.content.length > 60 ? '...' : ''}</div>
                ${c.error_log ? `<div style="color:var(--danger); font-size:0.7rem; margin-top:5px;">ERROR: ${c.error_log}</div>` : ''}
                ${c.result_data ? `<div style="color:var(--primary); font-size:0.7rem; margin-top:5px; font-family:monospace;">RESULT: ${JSON.stringify(c.result_data)}</div>` : ''}
            </div>
        `;
    }).join('') || '<div style="padding:40px; text-align:center; color:#444;">NO COMMAND HISTORY FOR SELECTED CLUSTER</div>';
}

